package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="health_metrics") public class HealthMetric { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="blood_report_id",nullable=false) private BloodReport bloodReport; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="nutrient_id") private NutrientMaster nutrient; @Column(name="metric_name",length=150) private String metricName; @Column(name="metric_value",precision=10,scale=2) private BigDecimal metricValue; @Column(length=20) private String unit; @Enumerated(EnumType.STRING) @Column(length=10) private Status status; public enum Status { LOW,NORMAL,HIGH } }
